import { defineComponentStyle } from "@yamada-ui/react"

export const closeButtonStyle = defineComponentStyle({
  defaultProps: {
    size: "xs",
    variant: "ghost",
  },
})

export type CloseButtonStyle = typeof closeButtonStyle

import { assert } from "vitest"
import { a11y, page, render } from "#test/browser"
import { CloseButton } from "./close-button"

describe("<CloseButton />", () => {
  test("renders component correctly", async () => {
    await a11y(<CloseButton />)
  })

  test("sets `displayName` correctly", () => {
    expect(CloseButton.displayName).toBe("CloseButton")
  })

  test("sets `className` correctly", async () => {
    await render(<CloseButton />)

    await expect
      .element(page.getByRole("button"))
      .toHaveClass("ui-close-button")
  })

  test("renders HTML tag correctly", async () => {
    await render(<CloseButton />)

    expect(page.getByRole("button").element().tagName).toBe("BUTTON")
  })

  test("has the proper aria attributes", async () => {
    await render(<CloseButton />)

    await expect.element(page.getByLabelText("Close")).toBeInTheDocument()
  })

  test("should call onClick", async () => {
    const onClickMock = vi.fn()
    const { user } = await render(<CloseButton onClick={onClickMock} />)

    await user.click(page.getByRole("button"))

    expect(onClickMock).toHaveBeenCalledTimes(1)
  })

  test("should not call onClick", async () => {
    const onClickMock = vi.fn()
    await render(<CloseButton disabled onClick={onClickMock} />)

    const button = page.getByRole("button").element()
    assert(button instanceof HTMLElement)

    button.click()

    expect(onClickMock).toHaveBeenCalledTimes(0)
  })
})

"use client"

import type { HTMLProps, WithoutThemeProps } from "@yamada-ui/react"
import type { IconButtonProps } from "../button"
import type { CloseButtonStyle } from "./close-button.style"
import { createComponent } from "@yamada-ui/react"
import { useI18n } from "../../providers/i18n-provider"
import { IconButton } from "../button"
import { XIcon } from "../icon"
import { closeButtonStyle } from "./close-button.style"

export interface CloseButtonProps
  extends
    Omit<WithoutThemeProps<IconButtonProps, CloseButtonStyle>, "aria-label">,
    Pick<HTMLProps<"button">, "aria-label"> {}

const {
  PropsContext: CloseButtonPropsContext,
  usePropsContext: useCloseButtonPropsContext,
  withContext,
} = createComponent<CloseButtonProps, CloseButtonStyle>(
  "close-button",
  closeButtonStyle,
)

export { CloseButtonPropsContext, useCloseButtonPropsContext }

/**
 * `CloseButton` is a component used primarily to trigger the close functionality of a component.
 *
 * @see https://yamada-ui.com/docs/components/close-button
 */
export const CloseButton = withContext<"button", CloseButtonProps>(IconButton)(
  undefined,
  ({ children, icon, ...rest }) => {
    const { t } = useI18n("closeButton")

    return {
      "aria-label": t("Close"),
      children: children || icon || <XIcon />,
      ...rest,
    }
  },
)
